func appendExecutionRoutingIntentEvidence(store BeadEventAppender, target bead.Bead, report ExecuteBeadReport, createdAt time.Time) {
	if store == nil || target.ID == "" {
		return
	}
	intent := escalation.ParseExecutionHint(&target)
	body := map[string]any{
		"bead_id":                 target.ID,
		"attempt_id":              report.AttemptID,
		"routing_intent_source":   string(intent.Source),
		"requested_tier":          string(intent.RequestedTier),
		"smart_justification":     intent.SmartJustification,
		"actual_harness":          report.Harness,
		"actual_provider":         report.Provider,
		"actual_model":            report.Model,
		"actual_power":            report.ActualPower,
		"routing_intent_degraded": false,
		"routing_intent_note":     "",
		"rejected_route_pins":     intent.RejectedRoutePins,
	}
	degraded := false
	note := ""
	if intent.Source == escalation.ExecutionIntentSourceBeadHint && intent.RequestedTier == escalation.TierSmart && strings.TrimSpace(intent.SmartJustification) == "" {
		degraded = true
		note = "missing SMART JUSTIFICATION"
	}
	if report.Harness == "" || report.Model == "" {
		degraded = true
		if note == "" {
			note = "actual route facts unavailable"
		}
	}
	body["routing_intent_degraded"] = degraded
	body["routing_intent_note"] = note
	data, err := json.Marshal(body)
	if err != nil {
		return
	}
	summary := fmt.Sprintf("source=%s tier=%s", intent.Source, intent.RequestedTier)
	if report.Model != "" {
		summary += " model=" + report.Model
	}
	if report.Harness != "" {
		summary += " harness=" + report.Harness
	}
	if degraded && note != "" {
		summary += " note=" + note
	}
	_ = store.AppendEvent(target.ID, bead.BeadEvent{
		Kind:      "execution-routing-intent",
		Summary:   summary,
		Body:      string(data),
		Actor:     "ddx",
		Source:    "ddx agent execute-loop",
		CreatedAt: createdAt,
	})
}

func appendPreDispatchLintEvent(store BeadEventAppender, beadID string, result LintResult, lintErr error, threshold int, actor string, createdAt time.Time) {
	if store == nil || beadID == "" {
		return
	}
	body := map[string]any{
		"score":           result.Score,
		"rationale":       result.Rationale,
		"suggested_fixes": result.SuggestedFixes,
		"waivers_applied": result.WaiversApplied,
	}
	summary := fmt.Sprintf("score=%d", result.Score)
	if threshold > 0 {
		body["threshold_score"] = threshold
	}
	if lintErr != nil {
		body["warning"] = lintErr.Error()
		summary = "warning " + summary
	} else if threshold > 0 && result.Score < threshold {
		body["dispatch_blocked"] = true
	}
	if encoded, err := json.Marshal(body); err == nil {
		_ = store.AppendEvent(beadID, bead.BeadEvent{
			Kind:      "bead-quality.lint",
			Summary:   summary,
			Body:      string(encoded),
			Actor:     actor,
			Source:    "ddx agent execute-loop",
			CreatedAt: createdAt,
		})
		return
	}
	parts := []string{
		fmt.Sprintf("score=%d", result.Score),
		"rationale=" + result.Rationale,
		fmt.Sprintf("suggested_fixes=%v", result.SuggestedFixes),
		fmt.Sprintf("waivers_applied=%v", result.WaiversApplied),
	}
	if threshold > 0 {
		parts = append(parts, fmt.Sprintf("threshold_score=%d", threshold))
	}

package agentmetrics

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

const (
	runStoreSubdir = ".ddx/exec/runs"
	bundlesSubdir  = ".ddx/executions"
)

// LoadAttempts scans the FEAT-010 run-store first, then .ddx/executions
// bundles, and returns one Attempt per execute-bead try. When the same
// AttemptID appears in both sources the run-store record wins. Attempts
// are returned sorted by StartedAt ascending (newest last) so callers
// computing windowed aggregations can take a tail slice.
func LoadAttempts(workingDir string) ([]Attempt, error) {
	enrich, err := loadRoutingEnrichment(workingDir)
	if err != nil {
		return nil, err
	}

	out := make([]Attempt, 0, 64)
	seen := make(map[string]bool)

	rs, err := loadFromRunStore(workingDir)
	if err != nil {
		return nil, err
	}
	for _, a := range rs {
		applyEnrichment(&a, enrich)
		a.Bucket = ClassifyBucket(a.Status)
		a.Tier = TierKey(a.Harness, a.Model)
		out = append(out, a)
		seen[a.AttemptID] = true
	}

	bd, err := loadFromBundles(workingDir)
	if err != nil {
		return nil, err
	}
	for _, a := range bd {
		if seen[a.AttemptID] {
			continue
		}
		applyEnrichment(&a, enrich)
		a.Bucket = ClassifyBucket(a.Status)
		a.Tier = TierKey(a.Harness, a.Model)
		out = append(out, a)
		seen[a.AttemptID] = true
	}

	sort.SliceStable(out, func(i, j int) bool {
		return out[i].StartedAt.Before(out[j].StartedAt)
	})
	return out, nil
}

// TierKey is the canonical "harness/model" tier label used by other Story
// 11 surfaces. An empty model collapses to just the harness.
func TierKey(harness, model string) string {
	if model == "" {
		return harness
	}
	return harness + "/" + model
}

// runRecord mirrors the FEAT-010 run-store JSON shape (subset). Mirrors
// server/state_runs.go runRecord; intentionally not shared so this package
// stays free of the server import graph.
type runRecord struct {
	ID          string  `json:"id"`
	Layer       string  `json:"layer"`
	Status      string  `json:"status"`
	Outcome     string  `json:"outcome"`
	StartedAt   string  `json:"started_at"`
	CompletedAt string  `json:"completed_at"`
	BeadID      string  `json:"bead_id"`
	Harness     string  `json:"harness"`
	Provider    string  `json:"provider"`
	Model       string  `json:"model"`
	CostUSD     float64 `json:"cost_usd"`
	DurationMs  int     `json:"duration_ms"`
	ExitCode    int     `json:"exit_code"`
	TokensIn    int     `json:"tokens_in"`
	TokensOut   int     `json:"tokens_out"`
}

func loadFromRunStore(workingDir string) ([]Attempt, error) {
	dir := filepath.Join(workingDir, runStoreSubdir)
	entries, err := os.ReadDir(dir)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, fmt.Errorf("read run store: %w", err)
	}
	out := make([]Attempt, 0, len(entries))
	for _, entry := range entries {
		if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".json") {
			continue
		}
		raw, err := os.ReadFile(filepath.Join(dir, entry.Name()))
		if err != nil {
			continue
		}
		var rec runRecord
		if err := json.Unmarshal(raw, &rec); err != nil || rec.ID == "" {
			continue
		}
		// Only try-layer records correspond to execute-bead attempts.
		// Run-layer records (per-invocation harness sessions) are noise
		// for Story 11 aggregations; skip them. Empty layer is treated
		// as try for forward-compat with writers that omit it.
		layer := strings.ToLower(rec.Layer)
		if layer != "" && layer != "try" {
			continue
		}
		a := Attempt{
			AttemptID:    rec.ID,
			BeadID:       rec.BeadID,
			Harness:      rec.Harness,
			Provider:     rec.Provider,
			Model:        rec.Model,
			Status:       rec.Status,
			Outcome:      rec.Outcome,
			CostUSD:      rec.CostUSD,
			DurationMS:   rec.DurationMs,
			ExitCode:     rec.ExitCode,
			InputTokens:  rec.TokensIn,
			OutputTokens: rec.TokensOut,
			StartedAt:    parseTime(rec.StartedAt),
			FinishedAt:   parseTime(rec.CompletedAt),
			Source:       SourceRunStore,
		}
		out = append(out, a)
	}
	return out, nil
}

