		Disrupted:                   true,
		DisruptionReason:            "transport_error",
		OutcomeReason:               "transport",
		PredictedPower:              82,
		PredictedSpeedTPS:           35.5,
		PredictedCostUSDPer1kTokens: 0.012345,
		PredictedCostSource:         "catalog",
