	assert.True(t, shouldSuppressNoProgress(ExecuteBeadReport{
		Status:        ExecuteBeadStatusNoChanges,
		BaseRev:       "same",
		ResultRev:     "same",
		OutcomeReason: "tests_red",
	}))
